sql:
SELECT AVG(rating_score) AS Average_Rating_Score
FROM campaign_ratings
WHERE campaign_id = 1;

SELECT COUNT(DISTINCT entrant_company_id) AS number_of_companies_won
FROM campaigns
WHERE campaign_status = 'won';

SELECT c.company_name
FROM companies AS c
JOIN awards AS a ON c.company_id = a.award_id;

SELECT title_brand_product_service
FROM campaigns
WHERE campaign_id NOT IN (
  SELECT campaign_id
  FROM campaign_comments
);

SELECT campaign_id
FROM campaign_ratings
WHERE rating_score >= 5;

SELECT comment_text 
FROM campaign_comments 
WHERE campaign_id = 1;

SELECT campaign_id, title_brand_product_service, budget
FROM campaigns
WHERE budget = (SELECT MAX(budget) FROM campaigns);

SELECT award_ceremony_location
FROM awards
WHERE award_type = 'Short List';

SELECT title_brand_product_service
FROM campaigns
WHERE campaign_status = 'won';
